import{_ as n}from"./nyalra_kb-7135827b.js";import{_ as r}from"./nyalra_no_mono-8344e451.js";import{_ as c,W as s,X as _,Y as i,Z as e,$ as t,a0 as a,a2 as d,a1 as m,C as p}from"./framework-a4c02b8f.js";const f={},g=e("figure",null,[e("img",{src:n,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/a676fe98012c96c1e8353e0f0efa2b9f.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),u=m('<hr><p>在人均脑子较笨的职高，周围的同学大部分都是不良少年或者是看起来像不良少年的类型。还有一些是宅男。</p><p>所以，在这些宅男中，由于环境的影响，有些人渐渐变得有点不良了。嗯，其实这种走向比较叛逆，踏入歧途也是青春的一部分，这也没什么不好的。但是，这里必须要指出的是，「不能越过的界线」确实存在。</p><p>在班上有一个男生，从前是宅男，后来却转变成了不良少年。他把头发染得略带棕色，还开始像个烟民一样。而他越过的那条线就是纹身。惊人的是，他在不知不觉间兴奋地在手指上纹了一个巨大的十字架纹身。</p><p>结果发生了什么呢？不仅仅是他的形象是否俗气这个问题，更严重的是，他因此变得找不到工作。在九成的学生选择就业的职高，无法找到正常的工作对他来说是一个非常沉重的打击。</p><p>所以嘛，虽然他下定决心迈向了将纹身当作武器的独行者的道路，但问题是，他原本是个宅男，说实话并不是那种脸上充满威慑力的类型。这样一来，他就成了在「在学期间装着像不良，毕业后其实是个好好工作的人」的大家中的一个「只是无法找到工作的宅男」。他之后发生了什么我也不清楚，总之是一场悲惨的事件。</p><p>淘气的不良少年们本能地理解到了「影响就业的事情是危险的」。今天，我们来谈一谈这种「不能越过的界线」相关的事情。</p><p>在这个世界上有各种各样的界线。</p><p>当然，正是因为追逐刚刚被划定的边界，才有了激动人心、有趣和热情等等的感觉。但是，当然如果判断错误，就会像之前提到的宅男那样陷入困境。</p><p>判断的依据大概是「经验」和「人际关系」吧。</p><p>例如，暂且抛开在高中进行过不良行为的人不谈，职高充斥着从初中就开始乱来的不良少年。嗯，说不定在小学时期就已经开始闹事了。这些根本不学习的人们，纷纷涌向了那所被认为是只要把铅笔滚过试卷就能进的学校——职高。</p><p>由于已经有多次接受过指导的经验，他们学到了越过「不仅仅是会被惩罚」这条线后会发生的事情。</p><p>这些事情包括被叫家长、被送进少年院、被前辈欺负等等。他们能够通过老师的怒容判断出来，明白这已经不是「调皮捣蛋的小淘气」程度了。</p><p>而且更重要的是，他们会与其他同样有些独特的人成为朋友。因此迟早会有朋友的兄弟或前辈出现。通过观察这些前辈在就业或辍学时的选择，他们学到了将来也要这样生活。</p><p>通过过去的例子，他们知道在关键时刻可以用透明的耳环或创可贴来搪塞，称之为「耳环」还算可以接受。但在面试或体检时无法隐藏的纹身是不行的，这是一种暗中的默契。在此基础上，为了在情感冲动时也能生存下去，他们培养了自己的坚强。这样，他们就能考虑并制定生存策略，应对界线的边缘，或者越过线后的情况。</p><p>这种「经验」和「人际关系」随着成年而变得越来越难以把握，有时在互联网上，嘲笑或诋毁会越过「不能只当作笑话的线」。或者，过于挑战界线的游戏可能导致人们自然而然地疏远。做坏事、引起不良注意，虽然能轻松地吸引人群，但也伴随着这样的风险，是一把双刃剑。</p><p>所以，我们不要做任何坏事！我不想说老套的说教或空话。 但即便是那些被曝光的纹身宅男和过激诽谤的宅宅们，最初也只是抱着轻松的心态去做的。</p><p>虽然在心里嘀咕着「为什么只有我！」但仔细观察时，你会发现，不良分子也有他们自己的规矩，除了那些立志终身当不良分子、充满斗志的家伙之外，他们不轻易入纹身。这种微妙的平衡通常很难被明确规定。</p><p>当有人告诉你「随便就可以」的时候，我们并不能准确衡量「随便」的程度。一旦掉以轻心，可能会遭遇意料之外的问题。社会和人际关系总是潜藏着这种危险性。</p><p>当别人问你「你知道我为什么生气吗？」时，实际上可能是因为你一直在触碰那条勉强不可逾越的底线。而这在犯事人看来，可能只是属于「打情骂俏」或者「幽默」范畴的事情。这真的很令人难过。</p><p>通过多次经历这样的事情，我学到了很多，虽然你可能会想，「说了这么多，到底要我怎么办！」但或许在这篇文章中，有人能够找到一些启示，这也是我写这些的初衷。</p><p>世界上有很多看不见的规则，这让人感到非常害怕，互联网也一样。</p><hr><p><img src="'+r+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/3d54130310ab57fa6a7ada66e2cd0c51.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/59a18de80bd1e306c50d5af256cf9675.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/3c1d548a4e64bd0b90f512e270bdd6d3.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【小叽（ちぃ）的粘土人】记得应该是小叽。虽然上一回说到「对美少女角色的兴趣淡了」，但是当小时候喜欢的美少女被立体化时，我就会立刻被吸引，陷入自己无法摆脱的怀旧趣味老头感中。</p></blockquote>',25);function b(y,x){const o=p("ExternalLinkIcon"),l=p("RouterLink");return s(),_("div",null,[i(" more "),g,e("p",null,[t("原文链接："),e("a",h,[t("第41回／超えちゃいけないライン"),a(o)])]),e("blockquote",null,[k,e("p",null,[a(l,{to:"/posts/Translate/nyalra_kb_40.html"},{default:d(()=>[t("【奈亚拉面壁自语】第40回｜逐渐远去的对美少女角色的兴趣【230822】")]),_:1})])]),u])}const V=c(f,[["render",b],["__file","nyalra_kb_41.html.vue"]]);export{V as default};
